var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"시체가 일어나는 경우?","JPN":"死体が起き上がる場合？","ENG":"A corpse rising from the dead?","TWN":"屍體復活？"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"너도 알겠지만, 침식 지대에서 사람이 죽으면 대부분 침식체가 돼.","JPN":"あなたも知っているとおり、侵食地帯で人が死ぬとだいたいは侵食体になるわ。","ENG":"You already know this, but when someone dies in a Corrupted Area, they usually turn into a C.O.","TWN":"你也知道，在侵蝕地帶人死後大多數會變成侵蝕體。"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"시체가 형태를 유지한 채 침식체가 되는 경우가 있긴 하지만.","JPN":"死体が形を維持したまま侵食体になる場合もあるけど。","ENG":"There are cases where the body retains its form after becoming a C.O...","TWN":"雖然有時候屍體變成侵蝕體後，會保持原來的狀態。"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"흔한 경우는 아니지.","JPN":"滅多にないわね。","ENG":"But it's rare.","TWN":"但這種情況並不常見。"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"네크로멘시 능력, 혹은 그 능력을 가진 아티팩트를 사용했을 경우.","JPN":"ネクロマンシー能力、あるいはその能力を持っているアーティファクトを使用した場合。","ENG":"Unless necromancy is involved, or an Artifact with that power is being used.","TWN":"只有在使用死靈術能力，或使用擁有該能力的神器時，"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"죽은 자를 살리는 비술을 알고 있는 경우.","JPN":"死んだ者を蘇らせる秘術を知っている場合。","ENG":"Or if someone possesses the knowledge of resurrection magic.","TWN":"或是復活死者的秘術。"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"또 다른 경우는 너도 알고 있는…….","JPN":"もう1つの場合は、あなたも知っているように……","ENG":"And of course, there's another possibility you're well aware–","TWN":"還有另一個情況你應該也知道……"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아뇨. 그 정도면 충분해요.","JPN":"いいえ。そのくらいで十分です。","ENG":"No, that's enough.","TWN":"不，這樣就夠了。"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"결론은, 진짜 유령이나 귀신 같은 건 없는 거니까.","JPN":"結論は、本物の幽霊とかお化けはいないということですから。","ENG":"The point is, there are no actual ghosts or evil spirits.","TWN":"結論是，根本沒有真正的幽靈或鬼怪。"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그러다가 진짜 귀신이 나타나면 어쩌려고 그럴까?","JPN":"そんなこと言って本物のお化けが出たらどうするの？","ENG":"What if a real ghost shows up?","TWN":"要是這樣真的引來鬼魂怎麼辦？"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"진짜 귀신이 어딨어요. 다 침식체를 잘못 본 거지.","JPN":"お化けなんていませんよ。全部侵食体の見間違いでしょう。","ENG":"There's no such thing. People just mistake C.O.s for ghosts.","TWN":"哪裡會有真正的鬼啊，肯定是錯看成侵蝕體了。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"물론, 그런 겁쟁이들이 많을수록 저는 좋죠.","JPN":"もちろん、そんな臆病者が多ければ多いほど私にはいいことです。","ENG":"But hey, the more cowards there are, the better it is for me.","TWN":"膽小鬼越多越好。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래야 돈을 더 많이 벌 테니.","JPN":"もっと稼げますしね。","ENG":"Just means more profit.","TWN":"這樣才能賺更多的錢。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래. 퇴마사의 신조가 그 정도는 돼야 먹고 살지.","JPN":"そう。そのくらいの信条でないと、エクソシストとしては生きていけないわね。","ENG":"Well, an exorcist needs to have that kind of mindset to make a living.","TWN":"沒錯，驅魔師至少要有這種程度的信念才能生存下去。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 섭섭한 말씀을.","JPN":"何を他人事のように。","ENG":"Oh, come on.","TWN":"你說的這些話真讓人傷心。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 만약 진짜 혹시라도 귀신이 있으면 하고 싶은 게 있긴 해요.","JPN":"あ、もし本当にお化けがいるならやってみたいことはあります。","ENG":"By the way, if ghosts were actually real, there's something I'd like to try.","TWN":"啊，如果真的有鬼的話，我倒是有些想做的事情。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"죽기 전에 숨겨둔 유산이나 재물을 뜯어내는 거죠.","JPN":"生前に隠しておいた遺産とか財産を巻き上げてやるんです。","ENG":"I'd get them to cough up whatever treasures they stashed away before they died.","TWN":"在他們死之前，把他們藏起來的遺產或財物榨乾。"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어차피 걔네는 현세의 물건은 필요 없을 거잖아요.","JPN":"どうせあいつらに現世のものは要らないでしょう？","ENG":"I mean, they don't need worldly possessions anymore, do they?","TWN":"反正這些東西他們也帶不走。"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흐, 흐흐흐…… 생각만 해도 군침이…….","JPN":"ふ、ふふふ……考えただけでも笑いが……","ENG":"Heh... Hehehe... Just thinking about it makes my mouth water...","TWN":"嘿，嘿嘿嘿……光是想想就讓人流口水……"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"여기서 뭘 하고 있는 건가?","JPN":"ここで何をしているのかね？","ENG":"What are you doing over there?","TWN":"你在這裡做什麼？"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"히이익!","JPN":"ひいいっ！","ENG":"Eeeep!","TWN":"哎呀！"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"화장실에 다녀온다더니, 1시간이 지나도록 소식이 없어서 말일세.","JPN":"用を足しに行ってから、小1時間も戻らないのでね。","ENG":"You said you were going to the bathroom, but it's been an hour.","TWN":"說是去上廁所，結果一個小時過去了還沒消息。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 출발하기 전에 확인해야 할 것들이 있어서 말이죠.","JPN":"あ、出発する前に確認しないといけないものがありまして。","ENG":"Oh, I just needed to check a few things before we head out.","TWN":"啊，出發之前有些事情需要確認一下。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};